import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * 🧬 Dr. Generic — PhD in Generics & Type Algebra (TypeScript)
 * Generated by Sovereign Forge.
 */
export class GenericPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "generic";
        this.name = "Generic";
        this.emoji = "🧬";
        this.role = "PhD TypeScript Type Algebraist";
        this.phd_identity = "Generics & Type Algebra (TypeScript)";
        this.stack = "TypeScript";
        this.healingPrompt = "Fix the following generic programming or type abstraction issue. Improve generic constraints and resolve type erasure problems. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".tsx"],
            rules: [
          {
                    "regex": "<[^>]*<[^>]*<[^>]*>>",
                    "issue": "Complexidade: Generics com 3+ níveis de aninhamento — simplificar com type aliases.",
                    "severity": "medium"
          },
          {
                    "regex": "extends\\s+infer\\s+\\w+.*extends\\s+infer",
                    "issue": "Magia Negra: Múltiplos \"infer\" condicionais — difícil de manter.",
                    "severity": "high"
          },
          {
                    "regex": "type\\s+\\w+<[^>]*>\\s*=\\s*\\w+<[^>]*>\\s*extends\\s",
                    "issue": "Tipo Condicional: Conditional type — verifique se não há alternativa simples.",
                    "severity": "low"
          },
          {
                    "regex": "as\\s+unknown\\s+as\\s+",
                    "issue": "Double Cast: \"as unknown as X\" — forte indicador de design errado.",
                    "severity": "high"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Generic operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Generic, PhD em Generics & Type Algebra (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
